#include<iostream>#include<vector>#include<string>#define ll long longusing namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        string s;        cin>>s;        ll n = s.size();        ll maxi=0;        ll i=0;        while(i<n){            if(s[i]=='0'){                i++;                continue;            }            ll j=i+1;            while(j<n && s[j]=='1'){                j++;            }            maxi = max(maxi,j-i);            i=j;        }        if(maxi==n){            cout<<n * n<<"\n";            continue;        }            if(s[0]=='1' && s[n-1]=='1'){                ll cnt=0;                ll i=0;                while(i<n && s[i]=='1'){                    cnt++;                    i++;                }                ll j=n-1;                while(j>=i && s[j]=='1'){                    cnt++;                    j--;                }                maxi= max(maxi,cnt);                            }            maxi++;            ll temp= (maxi + 1)/2;            cout<<(temp) * (maxi/2)<<"\n";            } }